CREATE TABLE roles (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), code text NOT NULL UNIQUE, description text NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE user_role_assignments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id text NOT NULL REFERENCES "user"(user_id), role_id uuid NOT NULL REFERENCES roles(id), granted_by_user_id text REFERENCES "user"(user_id), granted_at timestamptz NOT NULL DEFAULT now(), revoked_by_user_id text REFERENCES "user"(user_id), revoked_at timestamptz, reason text, CONSTRAINT user_role_assignments_revoke_pair_chk CHECK ((revoked_at IS NULL) = (revoked_by_user_id IS NULL)));
CREATE UNIQUE INDEX user_role_assignments_active_uidx ON user_role_assignments(user_id, role_id) WHERE revoked_at IS NULL;
CREATE INDEX user_role_assignments_user_idx ON user_role_assignments(user_id);

CREATE TABLE wallets (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id text NOT NULL UNIQUE REFERENCES "user"(user_id), spending_balance_baht bigint NOT NULL DEFAULT 0, earnings_balance_baht bigint NOT NULL DEFAULT 0, held_for_jobs_baht bigint NOT NULL DEFAULT 0, reserved_for_payouts_baht bigint NOT NULL DEFAULT 0, status text NOT NULL DEFAULT 'ACTIVE', created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT wallets_nonnegative_balances_chk CHECK (spending_balance_baht >= 0 AND earnings_balance_baht >= 0 AND held_for_jobs_baht >= 0 AND reserved_for_payouts_baht >= 0));
CREATE TABLE wallet_status_history (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), wallet_id uuid NOT NULL REFERENCES wallets(id), from_status text, to_status text NOT NULL, actor_user_id text REFERENCES "user"(user_id), reason text, occurred_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX wallet_status_history_wallet_idx ON wallet_status_history(wallet_id, occurred_at);
CREATE TABLE ledger_accounts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), code text NOT NULL UNIQUE, type text NOT NULL, currency text NOT NULL DEFAULT 'THB', wallet_id uuid REFERENCES wallets(id), user_id text REFERENCES "user"(user_id), created_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT ledger_accounts_currency_chk CHECK (currency = 'THB'), CONSTRAINT ledger_accounts_owner_pair_chk CHECK ((wallet_id IS NULL) = (user_id IS NULL)));
CREATE UNIQUE INDEX ledger_accounts_wallet_type_uidx ON ledger_accounts(wallet_id, type) WHERE wallet_id IS NOT NULL;
CREATE TABLE idempotency_keys (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), principal_user_id text NOT NULL REFERENCES "user"(user_id), operation_scope text NOT NULL, key text NOT NULL, request_hash text NOT NULL, resource_type text, resource_id text, response_status integer, response_body jsonb, created_at timestamptz NOT NULL DEFAULT now(), expires_at timestamptz NOT NULL, CONSTRAINT idempotency_keys_principal_scope_key_uq UNIQUE(principal_user_id, operation_scope, key));
CREATE INDEX idempotency_keys_expiry_idx ON idempotency_keys(expires_at);
CREATE TABLE ledger_transactions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), business_reference text NOT NULL UNIQUE, event_type text NOT NULL, idempotency_key_id uuid UNIQUE REFERENCES idempotency_keys(id), correction_of_transaction_id uuid REFERENCES ledger_transactions(id), created_by_user_id text REFERENCES "user"(user_id), description text, created_at timestamptz NOT NULL DEFAULT now(), sealed_at timestamptz);
CREATE TABLE ledger_postings (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), transaction_id uuid NOT NULL REFERENCES ledger_transactions(id), account_id uuid NOT NULL REFERENCES ledger_accounts(id), amount_baht bigint NOT NULL, currency text NOT NULL DEFAULT 'THB', created_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT ledger_postings_nonzero_chk CHECK (amount_baht <> 0), CONSTRAINT ledger_postings_currency_chk CHECK (currency = 'THB'));
CREATE INDEX ledger_postings_transaction_idx ON ledger_postings(transaction_id);
CREATE INDEX ledger_postings_account_idx ON ledger_postings(account_id, created_at);
CREATE TABLE earnings_conversions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id text NOT NULL REFERENCES "user"(user_id), amount_baht bigint NOT NULL CHECK (amount_baht > 0), ledger_transaction_id uuid NOT NULL UNIQUE REFERENCES ledger_transactions(id), created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE wallet_activities (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id text NOT NULL REFERENCES "user"(user_id), type text NOT NULL, status text NOT NULL, spending_delta_baht bigint NOT NULL DEFAULT 0, earnings_delta_baht bigint NOT NULL DEFAULT 0, job_held_delta_baht bigint NOT NULL DEFAULT 0, payout_reserved_delta_baht bigint NOT NULL DEFAULT 0, resource_type text, resource_id text, occurred_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX wallet_activities_user_time_idx ON wallet_activities(user_id, occurred_at);
CREATE TABLE wallet_adjustments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), wallet_id uuid NOT NULL REFERENCES wallets(id), admin_user_id text NOT NULL REFERENCES "user"(user_id), compartment text NOT NULL, amount_baht bigint NOT NULL CHECK (amount_baht <> 0), reason text NOT NULL, ledger_transaction_id uuid NOT NULL UNIQUE REFERENCES ledger_transactions(id), created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE amounts_owed (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id text NOT NULL REFERENCES "user"(user_id), amount_baht bigint NOT NULL, recovered_baht bigint NOT NULL DEFAULT 0, reason text NOT NULL, source_type text NOT NULL, source_id text, status text NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT amounts_owed_range_chk CHECK (amount_baht > 0 AND recovered_baht >= 0 AND recovered_baht <= amount_baht));

CREATE TABLE money_policy_revisions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), revision bigint NOT NULL UNIQUE, minimum_top_up_baht bigint NOT NULL, maximum_top_up_baht bigint NOT NULL, minimum_funded_job_baht bigint NOT NULL, maximum_funded_job_baht bigint NOT NULL, minimum_earnings_conversion_baht bigint NOT NULL, maximum_earnings_conversion_baht bigint NOT NULL, minimum_payout_baht bigint NOT NULL, maximum_payout_baht bigint NOT NULL, platform_fee_bps bigint NOT NULL, dispute_two_person_threshold_baht bigint NOT NULL, quote_lifetime_seconds bigint NOT NULL, review_window_seconds bigint NOT NULL, default_application_window_seconds bigint NOT NULL, authored_by_user_id text REFERENCES "user"(user_id), reason text NOT NULL, effective_from timestamptz NOT NULL, effective_until timestamptz, created_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT money_policy_limits_chk CHECK (minimum_top_up_baht > 0 AND maximum_top_up_baht >= minimum_top_up_baht AND minimum_funded_job_baht > 0 AND maximum_funded_job_baht >= minimum_funded_job_baht AND minimum_earnings_conversion_baht > 0 AND maximum_earnings_conversion_baht >= minimum_earnings_conversion_baht AND minimum_payout_baht > 0 AND maximum_payout_baht >= minimum_payout_baht), CONSTRAINT money_policy_fee_chk CHECK (platform_fee_bps BETWEEN 0 AND 10000), CONSTRAINT money_policy_durations_chk CHECK (quote_lifetime_seconds > 0 AND review_window_seconds > 0 AND default_application_window_seconds > 0), CONSTRAINT money_policy_range_chk CHECK (effective_until IS NULL OR effective_until > effective_from));

CREATE TABLE jobs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), employer_user_id text NOT NULL REFERENCES "user"(user_id), selected_worker_user_id text REFERENCES "user"(user_id), title text NOT NULL, description text NOT NULL, amount_baht bigint NOT NULL, platform_fee_bps bigint NOT NULL, platform_fee_baht bigint NOT NULL, worker_net_baht bigint NOT NULL, policy_revision_id uuid NOT NULL REFERENCES money_policy_revisions(id), status text NOT NULL, application_deadline_at timestamptz NOT NULL, work_deadline_at timestamptz NOT NULL, assigned_at timestamptz, completed_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT jobs_positive_amount_chk CHECK (amount_baht > 0 AND platform_fee_bps BETWEEN 0 AND 10000 AND platform_fee_baht >= 0 AND worker_net_baht >= 0 AND platform_fee_baht + worker_net_baht = amount_baht), CONSTRAINT jobs_deadlines_chk CHECK (application_deadline_at < work_deadline_at), CONSTRAINT jobs_distinct_parties_chk CHECK (selected_worker_user_id IS NULL OR selected_worker_user_id <> employer_user_id));
CREATE INDEX jobs_application_scheduler_idx ON jobs(status, application_deadline_at);
CREATE INDEX jobs_work_scheduler_idx ON jobs(status, work_deadline_at);
CREATE TABLE job_status_history (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), job_id uuid NOT NULL REFERENCES jobs(id), from_status text, to_status text NOT NULL, actor_user_id text REFERENCES "user"(user_id), source text NOT NULL, reason text, occurred_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX job_status_history_job_idx ON job_status_history(job_id, occurred_at);
CREATE TABLE job_applications (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), job_id uuid NOT NULL REFERENCES jobs(id), worker_user_id text NOT NULL REFERENCES "user"(user_id), message text NOT NULL, status text NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT job_applications_job_worker_uq UNIQUE(job_id, worker_user_id));
CREATE INDEX job_applications_worker_status_idx ON job_applications(worker_user_id, status);
CREATE TABLE job_application_status_history (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), application_id uuid NOT NULL REFERENCES job_applications(id), from_status text, to_status text NOT NULL, actor_user_id text REFERENCES "user"(user_id), source text NOT NULL, reason text, occurred_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX job_application_history_idx ON job_application_status_history(application_id, occurred_at);
CREATE TABLE work_submissions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), job_id uuid NOT NULL UNIQUE REFERENCES jobs(id), worker_user_id text NOT NULL REFERENCES "user"(user_id), summary text NOT NULL, status text NOT NULL, submitted_at timestamptz NOT NULL DEFAULT now(), review_deadline_at timestamptz NOT NULL);
CREATE INDEX work_submissions_review_scheduler_idx ON work_submissions(status, review_deadline_at);
CREATE TABLE work_submission_status_history (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), submission_id uuid NOT NULL REFERENCES work_submissions(id), from_status text, to_status text NOT NULL, actor_user_id text REFERENCES "user"(user_id), source text NOT NULL, reason text, occurred_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX work_submission_history_idx ON work_submission_status_history(submission_id, occurred_at);
CREATE TABLE disputes (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), job_id uuid NOT NULL UNIQUE REFERENCES jobs(id), opened_by_user_id text NOT NULL REFERENCES "user"(user_id), reason_code text NOT NULL, description text NOT NULL, amount_baht bigint NOT NULL CHECK (amount_baht > 0), status text NOT NULL, resolution_target_at timestamptz NOT NULL, resolved_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE dispute_status_history (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), dispute_id uuid NOT NULL REFERENCES disputes(id), from_status text, to_status text NOT NULL, actor_user_id text REFERENCES "user"(user_id), source text NOT NULL, reason text, occurred_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX dispute_status_history_idx ON dispute_status_history(dispute_id, occurred_at);
CREATE TABLE dispute_resolutions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), dispute_id uuid NOT NULL UNIQUE REFERENCES disputes(id), proposed_by_user_id text NOT NULL REFERENCES "user"(user_id), outcome text NOT NULL, reason text NOT NULL, amount_baht bigint NOT NULL CHECK (amount_baht > 0), policy_revision_id uuid NOT NULL REFERENCES money_policy_revisions(id), status text NOT NULL, ledger_transaction_id uuid UNIQUE REFERENCES ledger_transactions(id), created_at timestamptz NOT NULL DEFAULT now(), executed_at timestamptz);
CREATE TABLE dispute_resolution_approvals (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), resolution_id uuid NOT NULL UNIQUE REFERENCES dispute_resolutions(id), approver_user_id text NOT NULL REFERENCES "user"(user_id), decision text NOT NULL, reason text, decided_at timestamptz NOT NULL DEFAULT now());

CREATE TABLE top_up_quotes (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id text NOT NULL REFERENCES "user"(user_id), policy_revision_id uuid NOT NULL REFERENCES money_policy_revisions(id), credit_baht bigint NOT NULL, charged_fee_baht bigint NOT NULL, charged_tax_baht bigint NOT NULL, payment_total_baht bigint NOT NULL, provider_fee_satang bigint NOT NULL, provider_tax_satang bigint NOT NULL, provider_total_satang bigint NOT NULL, currency text NOT NULL DEFAULT 'THB', expires_at timestamptz NOT NULL, consumed_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT top_up_quotes_amounts_chk CHECK (credit_baht > 0 AND charged_fee_baht >= 0 AND charged_tax_baht >= 0 AND payment_total_baht = credit_baht + charged_fee_baht + charged_tax_baht AND provider_fee_satang >= 0 AND provider_tax_satang >= 0 AND provider_total_satang > 0), CONSTRAINT top_up_quotes_currency_chk CHECK (currency = 'THB'));
CREATE INDEX top_up_quotes_expiry_idx ON top_up_quotes(expires_at);
CREATE TABLE top_ups (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), internal_reference text NOT NULL UNIQUE, user_id text NOT NULL REFERENCES "user"(user_id), quote_id uuid NOT NULL UNIQUE REFERENCES top_up_quotes(id), provider text NOT NULL, provider_reference text UNIQUE, credit_baht bigint NOT NULL, charged_fee_baht bigint NOT NULL, charged_tax_baht bigint NOT NULL, payment_total_baht bigint NOT NULL, provider_fee_satang bigint NOT NULL, provider_tax_satang bigint NOT NULL, provider_total_satang bigint NOT NULL, currency text NOT NULL DEFAULT 'THB', qr_payload text, qr_expires_at timestamptz, status text NOT NULL, credited_ledger_transaction_id uuid UNIQUE REFERENCES ledger_transactions(id), created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT top_ups_amount_chk CHECK (credit_baht > 0 AND charged_fee_baht >= 0 AND charged_tax_baht >= 0 AND payment_total_baht = credit_baht + charged_fee_baht + charged_tax_baht AND provider_fee_satang >= 0 AND provider_tax_satang >= 0 AND provider_total_satang > 0), CONSTRAINT top_ups_currency_chk CHECK (currency = 'THB'));
CREATE INDEX top_ups_user_status_idx ON top_ups(user_id, status);
CREATE TABLE top_up_status_history (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), top_up_id uuid NOT NULL REFERENCES top_ups(id), from_status text, to_status text NOT NULL, provider_status text, actor_user_id text REFERENCES "user"(user_id), source text NOT NULL, reason text, occurred_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX top_up_status_history_idx ON top_up_status_history(top_up_id, occurred_at);
CREATE TABLE payout_accounts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id text NOT NULL REFERENCES "user"(user_id), recipient_type text NOT NULL, given_name text NOT NULL, surname text NOT NULL, relationship text NOT NULL, account_country text NOT NULL DEFAULT 'TH', account_currency text NOT NULL DEFAULT 'THB', bank_code text NOT NULL, account_number text NOT NULL, account_holder_name text NOT NULL, routing_type text NOT NULL, routing_value text NOT NULL, masked_last_four text NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), retired_at timestamptz, CONSTRAINT payout_accounts_country_currency_chk CHECK (account_country = 'TH' AND account_currency = 'THB'));
CREATE UNIQUE INDEX payout_accounts_active_user_uidx ON payout_accounts(user_id) WHERE retired_at IS NULL;
CREATE TABLE payout_quotes (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id text NOT NULL REFERENCES "user"(user_id), payout_account_id uuid NOT NULL REFERENCES payout_accounts(id), policy_revision_id uuid NOT NULL REFERENCES money_policy_revisions(id), receipt_baht bigint NOT NULL, maximum_fee_baht bigint NOT NULL, maximum_tax_baht bigint NOT NULL, maximum_debit_baht bigint NOT NULL, quoted_fee_satang bigint NOT NULL, quoted_tax_satang bigint NOT NULL, quoted_debit_satang bigint NOT NULL, currency text NOT NULL DEFAULT 'THB', expires_at timestamptz NOT NULL, consumed_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT payout_quotes_amount_chk CHECK (receipt_baht > 0 AND maximum_fee_baht >= 0 AND maximum_tax_baht >= 0 AND maximum_debit_baht = receipt_baht + maximum_fee_baht + maximum_tax_baht AND quoted_fee_satang >= 0 AND quoted_tax_satang >= 0 AND quoted_debit_satang > 0), CONSTRAINT payout_quotes_currency_chk CHECK (currency = 'THB'));
CREATE INDEX payout_quotes_expiry_idx ON payout_quotes(expires_at);
CREATE TABLE payouts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id text NOT NULL REFERENCES "user"(user_id), quote_id uuid NOT NULL UNIQUE REFERENCES payout_quotes(id), payout_account_id uuid NOT NULL REFERENCES payout_accounts(id), destination_recipient_type text NOT NULL, destination_given_name text NOT NULL, destination_surname text NOT NULL, destination_relationship text NOT NULL, destination_account_country text NOT NULL, destination_account_currency text NOT NULL, destination_bank_code text NOT NULL, destination_account_number text NOT NULL, destination_account_holder_name text NOT NULL, destination_routing_type text NOT NULL, destination_routing_value text NOT NULL, provider text NOT NULL, provider_reference text UNIQUE, principal_baht bigint NOT NULL, maximum_fee_baht bigint NOT NULL, maximum_tax_baht bigint NOT NULL, maximum_debit_baht bigint NOT NULL, actual_fee_satang bigint, actual_tax_satang bigint, actual_debit_satang bigint, currency text NOT NULL DEFAULT 'THB', status text NOT NULL, reserve_ledger_transaction_id uuid NOT NULL UNIQUE REFERENCES ledger_transactions(id), final_ledger_transaction_id uuid UNIQUE REFERENCES ledger_transactions(id), created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT payouts_amount_chk CHECK (principal_baht > 0 AND maximum_fee_baht >= 0 AND maximum_tax_baht >= 0 AND maximum_debit_baht = principal_baht + maximum_fee_baht + maximum_tax_baht), CONSTRAINT payouts_currency_chk CHECK (currency = 'THB' AND destination_account_country = 'TH' AND destination_account_currency = 'THB'));
CREATE UNIQUE INDEX payouts_active_user_uidx ON payouts(user_id) WHERE status IN ('CREATING','PENDING','AWAITING_RECONCILIATION');
CREATE TABLE payout_status_history (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), payout_id uuid NOT NULL REFERENCES payouts(id), from_status text, to_status text NOT NULL, provider_status text, actor_user_id text REFERENCES "user"(user_id), source text NOT NULL, reason text, occurred_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX payout_status_history_idx ON payout_status_history(payout_id, occurred_at);
CREATE TABLE payout_cancellation_attempts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), payout_id uuid NOT NULL REFERENCES payouts(id), admin_user_id text NOT NULL REFERENCES "user"(user_id), reason text NOT NULL, status text NOT NULL, provider_response jsonb, attempted_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX payout_cancellation_attempts_payout_idx ON payout_cancellation_attempts(payout_id, attempted_at);

CREATE TABLE provider_webhook_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), provider text NOT NULL, provider_event_id text NOT NULL, kind text NOT NULL, authenticated_at timestamptz NOT NULL, payload jsonb NOT NULL, payload_hash text NOT NULL, status text NOT NULL DEFAULT 'RECEIVED', attempts integer NOT NULL DEFAULT 0 CHECK (attempts >= 0), received_at timestamptz NOT NULL DEFAULT now(), claimed_at timestamptz, processed_at timestamptz, last_error text, CONSTRAINT provider_webhook_provider_event_uq UNIQUE(provider, provider_event_id));
CREATE INDEX provider_webhook_claim_idx ON provider_webhook_events(status, received_at);
CREATE TABLE provider_webhook_event_status_history (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), event_id uuid NOT NULL REFERENCES provider_webhook_events(id), from_status text, to_status text NOT NULL, reason text, error text, occurred_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX provider_webhook_history_idx ON provider_webhook_event_status_history(event_id, occurred_at);
CREATE TABLE reconciliation_runs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), provider text NOT NULL, period_start timestamptz NOT NULL, period_end timestamptz NOT NULL, internal_total_satang bigint NOT NULL, provider_total_satang bigint NOT NULL, difference_satang bigint NOT NULL, status text NOT NULL, started_by_user_id text REFERENCES "user"(user_id), started_at timestamptz NOT NULL DEFAULT now(), completed_at timestamptz, CHECK (period_end > period_start));
CREATE TABLE reconciliation_items (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), run_id uuid NOT NULL REFERENCES reconciliation_runs(id), type text NOT NULL, reference text NOT NULL, expected_satang bigint NOT NULL, actual_satang bigint NOT NULL, difference_satang bigint NOT NULL, status text NOT NULL, notes text);
CREATE INDEX reconciliation_items_run_idx ON reconciliation_items(run_id, status);
CREATE TABLE platform_controls (key text PRIMARY KEY, outbound_money_held boolean NOT NULL DEFAULT false, reconciliation_run_id uuid REFERENCES reconciliation_runs(id), reason text, changed_by_user_id text REFERENCES "user"(user_id), created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE scheduled_tasks (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), type text NOT NULL, dedupe_key text NOT NULL UNIQUE, aggregate_type text, aggregate_id text, run_at timestamptz NOT NULL, payload jsonb NOT NULL DEFAULT '{}'::jsonb, status text NOT NULL DEFAULT 'PENDING', attempts integer NOT NULL DEFAULT 0, max_attempts integer NOT NULL DEFAULT 10, locked_by text, locked_at timestamptz, lease_expires_at timestamptz, last_error text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CHECK (attempts >= 0 AND max_attempts > 0 AND attempts <= max_attempts));
CREATE INDEX scheduled_tasks_claim_idx ON scheduled_tasks(status, run_at);
CREATE TABLE scheduled_task_status_history (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), task_id uuid NOT NULL REFERENCES scheduled_tasks(id), from_status text, to_status text NOT NULL, source text NOT NULL, reason text, error text, occurred_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX scheduled_task_history_idx ON scheduled_task_status_history(task_id, occurred_at);
CREATE TABLE audit_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), actor_user_id text REFERENCES "user"(user_id), source text NOT NULL, action text NOT NULL, resource_type text NOT NULL, resource_id text, reason text, before jsonb, after jsonb, request_id text, trace_id text, ip_address inet, occurred_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX audit_events_resource_idx ON audit_events(resource_type, resource_id, occurred_at);
CREATE INDEX audit_events_actor_idx ON audit_events(actor_user_id, occurred_at);
